SELECT project_id, COUNT(simulation_id) AS total_simulations
FROM project_simulations
GROUP BY project_id;

SELECT simulation_id, model_id
FROM simulation_models_history
WHERE model_id = 1;

SELECT AVG(collaboration_count) AS average_collaborations_per_project
FROM (
    SELECT project_id, COUNT(*) AS collaboration_count
    FROM collaborations
    GROUP BY project_id
);

SELECT project_id, SUM(quantity) AS Total_Quantity
FROM project_components
GROUP BY project_id;

SELECT components.name, component_parameters.name, component_parameters.value, component_parameters.unit
FROM components
JOIN component_parameters ON components.component_id = component_parameters.component_id;
